import { useEffect, useState } from "react";
import socket from "../socket";

function Host() {
  const [players, setPlayers] = useState([]);
  const [scores, setScores] = useState({});
  const [gameStarted, setGameStarted] = useState(false);

  const [questions, setQuestions] = useState([]);
  const [current, setCurrent] = useState(0);

  // ✅ Load questions from backend
  useEffect(() => {
    fetch("http://localhost:5000/api/game")
      .then((res) => res.json())
      .then((data) => {
        console.log("Questions loaded:", data);
        setQuestions(data);
      })
      .catch((err) => console.log(err));
  }, []);

  // ✅ Socket listeners
  useEffect(() => {
    socket.on("playersUpdated", (data) => {
      console.log("Players updated:", data);
      setPlayers(data);
    });

    socket.on("scoreUpdated", (data) => {
      console.log("Scores updated:", data);
      setScores(data);
    });

    return () => {
      socket.off("playersUpdated");
      socket.off("scoreUpdated");
    };
  }, []);

  // ✅ Start game
  const startGame = () => {
    socket.emit("startGame");
    setGameStarted(true);
  };

  // ✅ Next question
  const nextQuestion = () => {
  socket.emit("nextQuestion"); // ✅ MUST EXIST
};

  return (
    <div>
      <h1>🎮 Host Dashboard</h1>

      {!gameStarted && (
        <button onClick={startGame}>Start Game</button>
      )}

      {/* ✅ Show Question */}
      {gameStarted && questions.length > 0 && current < questions.length && (
        <div>
          <h2>Question {current + 1}</h2>
          <h3>{questions[current].question}</h3>

          {questions[current].options.map((opt, i) => (
            <button key={i} style={{ display: "block", margin: "10px" }}>
              {opt}
            </button>
          ))}

          <button onClick={nextQuestion}>Next Question</button>
        </div>
      )}

      {/* ✅ Players */}
      <h3>Players</h3>
      {players.length === 0 ? (
        <p>No players</p>
      ) : (
        players.map((p, i) => <p key={i}>{p.name}</p>)
      )}

      {/* ✅ Scoreboard */}
      <h3>ScoreBoard</h3>
      {Object.keys(scores).length === 0 ? (
        <p>No scores yet</p>
      ) : (
        Object.entries(scores).map(([name, score], i) => (
          <p key={i}>
            {name}: {score}
          </p>
        ))
      )}
    </div>
  );
}

export default Host;
